const res = $input.first()?.json || {};
let ai_text = "";
try {
  ai_text = res.choices[0].message.content;
} catch(e) {
  ai_text = "IA ocupada, intentando de nuevo.";
}

// Persist context
const trigger = $node["Execute Workflow Trigger"].json;

return [{
  json: {
    success: true,
    data: {
      chat_id: trigger.chat_id || 5391760292,
      user_email: trigger.user_email || "baba.orere@gmail.com",
      start_time: "2026-03-02T14:00:00Z",
      ai_response: ai_text
    }
  }
}];

return [{
  json: {
    success: false,
    error_code: "AI_API_ERROR",
    error_message: "Error al contactar con el motor de IA",
    data: null,
    _meta: {
      source: "NN_03_AI_Agent",
      timestamp: new Date().toISOString(),
      workflow_id: "NN_03"
    }
  }
}];
